class OrderCalculator {
  private tempDiscount: number | null = null;

  applyDiscount(order: Order) {
    this.tempDiscount = this.lookupDiscount(order);
    order.total -= this.tempDiscount;
    this.tempDiscount = null;
  }

  calculateTax(order: Order) {
    // unrelated: uses no tempDiscount
    return order.total * 0.1;
  }

  private lookupDiscount(o: Order) { return 5; }
}

/* Version A */
class ReportGenerator {
  private intermediate: number | null = null;

  generate(data: Data) {
    this.intermediate = this.computeStep(data);
    const out = this.format(data, this.intermediate);
    this.intermediate = null;
    return out;
  }

  private computeStep(d: Data) { return 42; }
  private format(d: Data, n: number | null) { return `v:${n}`; }
}

/* Version B */
class ReportGeneratorV2 {
  generate(data: Data) {
    const intermediate = this.computeStep(data);
    return this.format(data, intermediate);
  }

  private computeStep(d: Data) { return 42; }
  private format(d: Data, n: number) { return `v:${n}`; }
}
